zoom = 0.9999;
rot = 0;
dx = 0;
dy = 0;
sx = 0.9999;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dec_m = pow (0.8, 30/fps); dec_s = pow (0.94, 30/fps);;
beat = bass+mid+treb;;
avg = avg*dec_s + beat*(1-dec_s);;
is_beat = ((beat) > (peak*8+1*avg)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_m;;
index = (index + is_beat) %16;;
index2 = (index2 + is_beat*bnot(index))%8;;
q20 = avg;;
q22 = max(0,peak-.0)+.01;;
q24 = is_beat;;
q27 = index +1;;
q28 = index2;;
p1 = dec_m * p1 + (1-dec_m) * index;;
p2 = dec_m * p2 + (1-dec_m) * p1;;
p1 = index;;
rot1 = rot1 + sin(p1*2)/fps * avg/5;;
rot2 = rot2 + cos(p1*2/3)/fps*avg/5;;
q1 = rot1;;
q2 = rot2;;
pulse = pulse + (bass>.8)/fps*(bass-.8)*16;;
q8 = int(pulse*16)%16;;
q9  = cos(q8)*3;;
q10 = sin(q8)*3;;
trig = is_beat * bnot(index%6);;
speed = .35 *pos_z*2 ;;
dir  = if (trig, dir + int(rand(3)-1.5)*3.1416/2, dir);;
dir_ = dec_m*dir_ + (1-dec_m)*dir;;
dir__ = dec_m*dir__ + (1-dec_m)*dir_;;
xpos = xpos + cos(dir_)/fps*speed +q24;;
ypos = ypos + sin(dir_)/fps*speed +q24;;
q5 = xpos;;
q6 = ypos;;
proxy = max(min(sin((q28%2)*q27+(xpos+ypos)),.5),-.5);;
xang =0*cos(dir); yang = 0*sin(dir);;
zang = dir__; ;;
pos_z = .5 + proxy/2;;
q29 = .02/pos_z;;
ox = 0; oy = 0; oz = pos_z;;
mx = ox*cos(zang) - oy*sin(zang);;
my = ox*sin(zang) + oy*cos(zang);;
ox = mx;oy = my;;
mx = ox*cos(yang) + oz*sin(yang);;
mz = - ox*sin(yang) + oz*cos(yang);;
ox = mx;oz = mz;;
my = oy*cos(xang) - oz*sin(xang);;
mz = oy*sin(xang) + oz*cos(xang);;
oy = my;oz = mz;;
